// // This module is designed to perform a logical OR operation on inputs A1 and A2, and then AND the result with the negation of input B1.
module my_module (
    Y ,
    A1,
    A2,
    B1
);

    output Y ;
    input  A1;
    input  A2;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign Y = (A1 & A2 & ~B1);

endmodule
